// X (Twitter) thought leaders. Pulled 14-day window each Fri 11am PT.
// max_items: items to request from Apify per handle. Apify dedups against Notion downstream.
// tier drives Claude relevance threshold.
return [
  // Tier S: highest analytical signal density (eval 2026-04-26)
  { json: { handle: 'random_walker',  display_name: 'Arvind Narayanan',  max_items: 60, tier: 'high' } },
  { json: { handle: 'hardmaru',        display_name: 'David Ha',           max_items: 60, tier: 'high' } },
  { json: { handle: 'sarahookr',       display_name: 'Sara Hooker',        max_items: 60, tier: 'high' } },
  { json: { handle: 'simonw',          display_name: 'Simon Willison',     max_items: 60, tier: 'high' } },
  { json: { handle: 'rasbt',           display_name: 'Sebastian Raschka',  max_items: 60, tier: 'high' } },
  // Tier A: secondary include
  { json: { handle: 'swyx',            display_name: 'Shawn Wang',         max_items: 40, tier: 'medium' } },
  { json: { handle: 'goodside',        display_name: 'Riley Goodside',     max_items: 40, tier: 'medium' } },
  { json: { handle: 'virattt',         display_name: 'Virat',              max_items: 40, tier: 'medium' } },
  { json: { handle: 'jeremyphoward',   display_name: 'Jeremy Howard',      max_items: 30, tier: 'medium' } },
  { json: { handle: 'DrJimFan',        display_name: 'Jim Fan',            max_items: 30, tier: 'medium' } },
  { json: { handle: 'sayashk',         display_name: 'Sayash Kapoor',      max_items: 30, tier: 'medium' } },
];

// kaitoeasyapi returns one item per tweet. Filter mock placeholders + retweets + replies. Field shape: snake_case nested (retweeted_tweet, quoted_tweet).
const TIER_BY_HANDLE = {
  'random_walker': 'high',
  'hardmaru': 'high',
  'sarahookr': 'high',
  'simonw': 'high',
  'rasbt': 'high',
  'swyx': 'medium',
  'goodside': 'medium',
  'virattt': 'medium',
  'jeremyphoward': 'medium',
  'drjimfan': 'medium',
  'sayashk': 'medium',
};
const HIGH_VOLUME = new Set(['simonw', 'rasbt', 'swyx', 'sarahookr', 'virattt']);
const WINDOW_DAYS = 14;
const cutoff = Date.now() - WINDOW_DAYS * 24 * 60 * 60 * 1000;
const items = $input.all();
const out = [];
for (const item of items) {
  const t = item.json;
  // Mock-tweet billing-floor filler: kaitoeasyapi returns these when query yields no real results
  if (t.type === 'mock_tweet' || t.id === -1 || t.id === '-1') continue;
  if (t.type && t.type !== 'tweet') continue;
  // Retweets nest as retweeted_tweet payload on this actor (no isRetweet boolean)
  if (t.retweeted_tweet) continue;
  if (t.isReply === true) continue;
  const text = (t.text || t.fullText || '').trim();
  if (!text) continue;
  const minLen = t.isQuote === true ? 30 : 80;
  if (text.length < minLen) continue;
  const raw = t.createdAt || t.created_at || '';
  const ts = raw ? new Date(raw).getTime() : 0;
  if (!ts || isNaN(ts) || ts < cutoff) continue;
  const author = t.author || {};
  const handle = String(author.userName || author.screen_name || author.username || '').toLowerCase();
  const likes = Number(t.likeCount || t.favoriteCount || 0);
  const replies = Number(t.replyCount || 0);
  const retweets = Number(t.retweetCount || 0);
  if (HIGH_VOLUME.has(handle)) {
    const engagement = likes + replies * 3;
    if (engagement < 30) continue;
  }
  const id = String(t.id || t.tweetId || t.id_str || '');
  let url = t.url || t.twitterUrl || '';
  if (!url && id && handle) url = 'https://x.com/' + handle + '/status/' + id;
  if (!url) continue;
  out.push({ json: {
    tweet_id: id,
    url: url,
    text: text.substring(0, 8000),
    is_quote: t.isQuote === true,
    quoted_text: (t.quoted_tweet && t.quoted_tweet.text) ? String(t.quoted_tweet.text).substring(0, 2000) : '',
    author_handle: handle,
    author_name: author.name || author.fullName || handle,
    posted_at: new Date(ts).toISOString(),
    likes: likes,
    replies: replies,
    retweets: retweets,
    views: Number(t.viewCount || 0),
    tier: TIER_BY_HANDLE[handle] || 'medium',
  }});
}
return out;

const tweets = $('Parse + Filter Tweets').all().map(it => it.json);
const existing = $input.all();
const existingIds = new Set();
const existingUrls = new Set();
for (const e of existing) {
  const results = (e.json.results) || [];
  for (const page of results) {
    const ep = (page.properties && page.properties.Episode && page.properties.Episode.rich_text) || [];
    for (const seg of ep) {
      const u = (seg.text && seg.text.link && seg.text.link.url) || '';
      if (u) existingUrls.add(u);
    }
    const cmt = (page.properties && page.properties.Comment && page.properties.Comment.rich_text) || [];
    for (const seg of cmt) {
      const c = (seg.text && seg.text.content) || '';
      const idMatch = c.match(/tweet_id: (\d+)/);
      if (idMatch) existingIds.add(idMatch[1]);
    }
  }
}
const newTweets = tweets.filter(p => !existingUrls.has(p.url) && !existingIds.has(p.tweet_id));
return newTweets.map(p => ({ json: p }));

